  phrases: [{ hi: "दो लोगों के लिए मेज़ चाहिए।", es: "Necesitamos una mesa para dos.", ipa: "do lo-gon ke li-ye mez cha-hi-ye" }, { hi: "मैं ऑर्डर देना चाहता हूँ।", es: "Quiero hacer un pedido.", ipa: "main or-dar de-na chaah-ta huun" }, { hi: "यह क्या है?", es: "¿Qué es esto?", ipa: "yah kya hai" }, { hi: "मुझे दाल और नान चाहिए।", es: "Quiero lentejas y naan.", ipa: "muj-he daal aur naan cha-hi-ye" }, { hi: "क्या इसमें मांस है?", es: "¿Esto tiene carne?", ipa: "kya is-men maans hai" }, { hi: "खाना स्वादिष्ट है।", es: "La comida está sabrosa.", ipa: "khaa-na svaa-dish-t hai" }],
