  phrases: [{ hi: "आज आप क्या सुझाव देंगे?", es: "¿Qué recomienda hoy?", ipa: "aaj aap kya su-jhaav den-ge" }, { hi: "मैं शहर घूमना चाहता हूँ।", es: "Quiero recorrer la ciudad.", ipa: "main sha-har ghuum-na chaah-ta huun" }, { hi: "यहाँ क्या मशहूर है?", es: "¿Qué es famoso aquí?", ipa: "ya-haan kya mash-huur hai" }, { hi: "कोई शांत जगह है?", es: "¿Hay algún lugar tranquilo?", ipa: "ko-i shaant ja-gah hai" }, { hi: "कल मैं मंदिर देखना चाहता हूँ।", es: "Mañana quiero ver el templo.", ipa: "kal main man-dir dekh-na chaah-ta huun" }, { hi: "यह बहुत मज़ेदार था।", es: "Esto fue muy divertido.", ipa: "yah ba-hut ma-ze-daar tha" }],
