  phrases: [{ hi: "क्या अंदर जा सकते हैं?", es: "¿Se puede entrar?", ipa: "kya an-dar jaa sak-te hain" }, { hi: "क्या जूते बाहर उतारने हैं?", es: "¿Hay que quitarse los zapatos afuera?", ipa: "kya juu-te baa-har u-taa-rne hain" }, { hi: "क्या फ़ोटो लेना ठीक है?", es: "¿Está bien tomar fotos?", ipa: "kya fo-to le-na thiik hai" }, { hi: "मैं नियम समझना चाहता हूँ।", es: "Quiero entender las reglas.", ipa: "main ni-yam sa-majh-na chaah-ta huun" }, { hi: "कृपया शांत रहिए।", es: "Por favor, guarde silencio.", ipa: "krip-ya shaant ra-hi-ye" }, { hi: "यह जगह बहुत पवित्र है।", es: "Este lugar es muy sagrado.", ipa: "yah ja-gah ba-hut pa-vi-tra hai" }],
