  phrases: [{ hi: "कृपया आसान हिंदी बोलिए।", es: "Por favor, hable hindi sencillo.", ipa: "krip-ya aa-saan hin-di bo-li-ye" }, { hi: "मुझे यह शब्द याद नहीं है।", es: "No recuerdo esta palabra.", ipa: "muj-he yah shabd yaad na-hin hai" }, { hi: "क्या आप लिख सकते हैं?", es: "¿Puede escribirlo?", ipa: "kya aap likh sak-te hain" }, { hi: "मैं समझने की कोशिश कर रहा हूँ।", es: "Estoy intentando entender.", ipa: "main sa-majh-ne kii ko-shish kar ra-ha huun" }, { hi: "अब मैं तैयार हूँ।", es: "Ahora estoy listo/a.", ipa: "ab main tai-yaar huun" }, { hi: "यात्रा अच्छी रही।", es: "El viaje fue bueno.", ipa: "yaa-tra ach-chhi ra-hi" }],
