var CONVERSATIONS_ES_HI = [
{ title: "Pedir en un café", scene: "Estás en un café pequeño en Connaught Place, Delhi. Quieres pedir té, agua fría y pagar la cuenta de forma educada.", lines: [{ who: "them", hi: "नमस्ते, आप क्या लेंगे?", es: "Hola, ¿qué va a tomar?" }, { who: "you", hi: "नमस्ते, मुझे एक चाय चाहिए।", es: "Hola, quiero un té." }, { who: "them", hi: "चीनी के साथ?", es: "¿Con azúcar?" }, { who: "you", hi: "नहीं, बिना चीनी, कृपया।", es: "No, sin azúcar, por favor." }, { who: "them", hi: "और कुछ?", es: "¿Algo más?" }, { who: "you", hi: "एक ठंडा पानी भी दीजिए।", es: "Deme también un agua fría." }, { who: "them", hi: "ठीक है, बैठिए।", es: "Está bien, siéntese." }, { who: "you", hi: "धन्यवाद, यहाँ वाई-फ़ाई है?", es: "Gracias, ¿hay Wi-Fi aquí?" }, { who: "them", hi: "हाँ, पासवर्ड बिल पर है।", es: "Sí, la contraseña está en la cuenta." }, { who: "you", hi: "अच्छा, बिल दीजिए, कृपया।", es: "Bien, la cuenta, por favor." }, { who: "them", hi: "कुल एक सौ रुपये हुए।", es: "El total son cien rupias." }, { who: "you", hi: "यह लीजिए, धन्यवाद।", es: "Tome, gracias." }] },
{ title: "Check-in en el hotel", scene: "Llegas a un hotel en Jaipur después de un viaje largo. Tienes una reserva y quieres confirmar si la habitación está lista.", lines: [{ who: "them", hi: "नमस्ते, होटल में आपका स्वागत है।", es: "Hola, bienvenido/a al hotel." }, { who: "you", hi: "नमस्ते, मेरी बुकिंग है।", es: "Hola, tengo una reserva." }, { who: "them", hi: "आपका नाम क्या है?", es: "¿Cuál es su nombre?" }, { who: "you", hi: "मेरा नाम कार्लोस गार्सिया है।", es: "Mi nombre es Carlos García." }, { who: "them", hi: "जी, आपकी बुकिंग दो रातों के लिए है।", es: "Sí, su reserva es por dos noches." }, { who: "you", hi: "कमरा तैयार है?", es: "¿La habitación está lista?" }, { who: "them", hi: "हाँ, कमरा तैयार है।", es: "Sí, la habitación está lista." }, { who: "you", hi: "चाबी दीजिए, कृपया।", es: "Deme la llave, por favor." }, { who: "them", hi: "यह आपकी चाबी है, कमरा नंबर दस।", es: "Esta es su llave, habitación número diez." }, { who: "you", hi: "क्या कमरे में वाई-फ़ाई है?", es: "¿Hay Wi-Fi en la habitación?" }, { who: "them", hi: "हाँ, पासवर्ड रिसेप्शन कार्ड पर है।", es: "Sí, la contraseña está en la tarjeta de recepción." }, { who: "you", hi: "बहुत धन्यवाद।", es: "Muchas gracias." }] },
{ title: "Preguntar direcciones", scene: "Estás cerca de una calle concurrida en Varanasi y buscas un templo famoso. Le preguntas a una persona local con respeto.", lines: [{ who: "you", hi: "माफ़ कीजिए, मंदिर कहाँ है?", es: "Disculpe, ¿dónde está el templo?" }, { who: "them", hi: "कौन सा मंदिर?", es: "¿Cuál templo?" }, { who: "you", hi: "काशी विश्वनाथ मंदिर।", es: "El templo Kashi Vishwanath." }, { who: "them", hi: "सीधे जाइए, फिर बाएँ मुड़िए।", es: "Vaya recto y luego gire a la izquierda." }, { who: "you", hi: "क्या यह पास है?", es: "¿Está cerca?" }, { who: "them", hi: "हाँ, पाँच मिनट पैदल।", es: "Sí, cinco minutos caminando." }, { who: "you", hi: "क्या रास्ता सुरक्षित है?", es: "¿El camino es seguro?" }, { who: "them", hi: "हाँ, लेकिन भीड़ बहुत है।", es: "Sí, pero hay mucha gente." }, { who: "you", hi: "अच्छा, धीरे चलना ठीक है।", es: "Bien, caminar despacio está bien." }, { who: "them", hi: "मंदिर गली के अंत में है।", es: "El templo está al final del callejón." }, { who: "you", hi: "आपकी मदद के लिए धन्यवाद।", es: "Gracias por su ayuda." }, { who: "them", hi: "कोई बात नहीं।", es: "No pasa nada." }] },
{ title: "Cena en un restaurante", scene: "Estás en un restaurante de Lucknow y quieres pedir comida vegetariana. Necesitas saber si un plato es picante y pedir la cuenta.", lines: [{ who: "them", hi: "नमस्ते, कितने लोग हैं?", es: "Hola, ¿cuántas personas son?" }, { who: "you", hi: "दो लोग हैं।", es: "Somos dos personas." }, { who: "them", hi: "आइए, यह मेज़ ठीक है?", es: "Pasen, ¿esta mesa está bien?" }, { who: "you", hi: "हाँ, धन्यवाद। मेन्यू दीजिए।", es: "Sí, gracias. Deme el menú." }, { who: "them", hi: "यह लीजिए।", es: "Aquí tiene." }, { who: "you", hi: "क्या यह शाकाहारी है?", es: "¿Esto es vegetariano?" }, { who: "them", hi: "हाँ, यह दाल और सब्ज़ी है।", es: "Sí, son lentejas y verduras." }, { who: "you", hi: "क्या यह बहुत तीखा है?", es: "¿Es muy picante?" }, { who: "them", hi: "थोड़ा तीखा है।", es: "Es un poco picante." }, { who: "you", hi: "ठीक है, दाल, नान और पानी दीजिए।", es: "Está bien, deme lentejas, naan y agua." }, { who: "them", hi: "ज़रूर।", es: "Claro." }, { who: "you", hi: "खाना बहुत अच्छा था, बिल दीजिए।", es: "La comida estuvo muy buena, la cuenta por favor." }] },
{ title: "Comprar billete de metro", scene: "Estás en una estación de metro en Delhi. Quieres comprar un billete, confirmar el andén y saber si el tren va a tu destino.", lines: [{ who: "them", hi: "नमस्ते, कहाँ जाना है?", es: "Hola, ¿a dónde quiere ir?" }, { who: "you", hi: "मुझे राजीव चौक जाना है।", es: "Quiero ir a Rajiv Chowk." }, { who: "them", hi: "एक टिकट या दो?", es: "¿Un billete o dos?" }, { who: "you", hi: "दो टिकट चाहिए।", es: "Necesito dos billetes." }, { who: "them", hi: "चालीस रुपये हुए।", es: "Son cuarenta rupias." }, { who: "you", hi: "क्या कार्ड चलेगा?", es: "¿Aceptan tarjeta?" }, { who: "them", hi: "हाँ, कार्ड चलेगा।", es: "Sí, aceptamos tarjeta." }, { who: "you", hi: "प्लेटफ़ॉर्म नंबर क्या है?", es: "¿Cuál es el número del andén?" }, { who: "them", hi: "प्लेटफ़ॉर्म नंबर दो।", es: "Andén número dos." }, { who: "you", hi: "क्या यह ट्रेन राजीव चौक जाती है?", es: "¿Este tren va a Rajiv Chowk?" }, { who: "them", hi: "हाँ, यह सीधी जाती है।", es: "Sí, va directo." }, { who: "you", hi: "धन्यवाद।", es: "Gracias." }] },
{ title: "Comprar en el mercado", scene: "Estás en un bazar de Jaipur mirando una bufanda azul. Quieres preguntar el precio, pedir otro color y negociar un poco.", lines: [{ who: "them", hi: "आइए, क्या चाहिए?", es: "Pase, ¿qué necesita?" }, { who: "you", hi: "यह कितने का है?", es: "¿Cuánto cuesta esto?" }, { who: "them", hi: "पाँच सौ रुपये।", es: "Quinientas rupias." }, { who: "you", hi: "बहुत महँगा है।", es: "Es muy caro." }, { who: "them", hi: "अच्छा कपड़ा है।", es: "Es buena tela." }, { who: "you", hi: "थोड़ा सस्ता कीजिए।", es: "Hágalo un poco más barato." }, { who: "them", hi: "ठीक है, चार सौ रुपये।", es: "Está bien, cuatrocientas rupias." }, { who: "you", hi: "क्या नीला रंग है?", es: "¿Tiene color azul?" }, { who: "them", hi: "हाँ, यह नीला है।", es: "Sí, este es azul." }, { who: "you", hi: "अच्छा, मैं इसे लेता हूँ।", es: "Bien, lo compro." }, { who: "them", hi: "बैग चाहिए?", es: "¿Quiere bolsa?" }, { who: "you", hi: "नहीं धन्यवाद।", es: "No, gracias." }] },
{ title: "En la farmacia", scene: "Estás en una farmacia en Mumbai porque te duele la cabeza. Quieres explicar el síntoma y preguntar cómo tomar la medicina.", lines: [{ who: "them", hi: "नमस्ते, क्या चाहिए?", es: "Hola, ¿qué necesita?" }, { who: "you", hi: "नमस्ते, मुझे दवा चाहिए।", es: "Hola, necesito medicina." }, { who: "them", hi: "किस लिए?", es: "¿Para qué?" }, { who: "you", hi: "मेरे सिर में दर्द है।", es: "Me duele la cabeza." }, { who: "them", hi: "बुखार है?", es: "¿Tiene fiebre?" }, { who: "you", hi: "नहीं, बुखार नहीं है।", es: "No, no tengo fiebre." }, { who: "them", hi: "यह दवा ले लीजिए।", es: "Tome esta medicina." }, { who: "you", hi: "यह दवा कैसे लेनी है?", es: "¿Cómo debo tomar esta medicina?" }, { who: "them", hi: "खाने के बाद, दिन में दो बार।", es: "Después de comer, dos veces al día." }, { who: "you", hi: "क्या डॉक्टर पास में है?", es: "¿Hay un médico cerca?" }, { who: "them", hi: "हाँ, अस्पताल सड़क के पास है।", es: "Sí, el hospital está cerca de la calle." }, { who: "you", hi: "धन्यवाद, आपने मदद की।", es: "Gracias, me ayudó." }] },
{ title: "Charla con una persona local", scene: "Estás sentado en un tren hacia Agra y una persona local inicia una conversación amable. Hablan de origen, viaje y recomendaciones.", lines: [{ who: "you", hi: "नमस्ते, क्या यह सीट खाली है?", es: "Hola, ¿está libre este asiento?" }, { who: "them", hi: "हाँ, बैठिए।", es: "Sí, siéntese." }, { who: "you", hi: "धन्यवाद, मैं स्पेन से हूँ।", es: "Gracias, soy de España." }, { who: "them", hi: "अच्छा, आप पहली बार भारत आए हैं?", es: "Ah, ¿es su primera vez en India?" }, { who: "you", hi: "हाँ, मैं पहली बार भारत आया हूँ।", es: "Sí, es mi primera vez en India." }, { who: "them", hi: "आपको भारत कैसा लग रहा है?", es: "¿Qué le parece India?" }, { who: "you", hi: "बहुत सुंदर और दिलचस्प है।", es: "Es muy bonita e interesante." }, { who: "them", hi: "आप आगरा में क्या देखेंगे?", es: "¿Qué verá en Agra?" }, { who: "you", hi: "मैं ताज महल देखना चाहता हूँ।", es: "Quiero ver el Taj Mahal." }, { who: "them", hi: "सुबह जल्दी जाइए, भीड़ कम होगी।", es: "Vaya temprano por la mañana, habrá menos gente." }, { who: "you", hi: "अच्छा सुझाव है, धन्यवाद।", es: "Es una buena recomendación, gracias." }, { who: "them", hi: "आपकी यात्रा अच्छी रहे।", es: "Que tenga buen viaje." }] }
];
